import{_ as a,c as r,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"429排查: 帳號輪換與錯誤處理 | Antigravity-Manager","description":"學習 Antigravity Tools 的 429 錯誤排查方法。掌握 QUOTA_EXHAUSTED、RATE_LIMIT_EXCEEDED 等錯誤的識別與處理，使用 Monitor 和 X-Account-Email 快速定位問題。","frontmatter":{"title":"429排查: 帳號輪換與錯誤處理 | Antigravity-Manager","sidebarTitle":"429錯誤：自動輪換帳號","subtitle":"429排查: 帳號輪換與錯誤處理","description":"學習 Antigravity Tools 的 429 錯誤排查方法。掌握 QUOTA_EXHAUSTED、RATE_LIMIT_EXCEEDED 等錯誤的識別與處理，使用 Monitor 和 X-Account-Email 快速定位問題。","tags":["FAQ","錯誤排查","帳號調度","429錯誤"],"prerequisite":["start-getting-started","advanced-scheduling"],"order":3},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"}'),i={name:"zh-tw/lbjlaq/Antigravity-Manager/faq/429-rotation/index.md"};function s(l,t,n,d,c,p){return e(),r("div",null,[...t[0]||(t[0]=[o(`<h1 id="_429-容量錯誤-帳號輪換的正確預期與模型容量耗盡的誤區" tabindex="-1">429/容量錯誤：帳號輪換的正確預期與模型容量耗盡的誤區 <a class="header-anchor" href="#_429-容量錯誤-帳號輪換的正確預期與模型容量耗盡的誤區" aria-label="Permalink to &quot;429/容量錯誤：帳號輪換的正確預期與模型容量耗盡的誤區&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>正確區分「配額不足」和「上游限流」，避免誤判</li><li>理解 Antigravity Tools 的自動輪換機制和預期行為</li><li>遇到 429 錯誤時，知道如何快速定位問題並優化設定</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><ul><li>看到返回 429 錯誤，誤以為是「模型沒容量了」</li><li>配了多個帳號，卻還是頻繁遇到 429，不知道是設定問題還是帳號問題</li><li>不清楚系統什麼時候會自動切換帳號，什麼時候會「卡住」</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><h3 id="什麼是-429-錯誤" tabindex="-1">什麼是 429 錯誤？ <a class="header-anchor" href="#什麼是-429-錯誤" aria-label="Permalink to &quot;什麼是 429 錯誤？&quot;">​</a></h3><p><strong>429 Too Many Requests</strong> 是 HTTP 狀態碼。在 Antigravity Tools 裡，429 不只代表「請求太頻繁」，還可能是配額耗盡、模型暫時過載等一類「你暫時用不了」的訊號。</p><div class="info custom-block"><p class="custom-block-title">代理會嘗試識別 429 的原因</p><p>代理會從響應體裡嘗試解析 <code>error.details[0].reason</code> 或 <code>error.message</code>，把 429 粗分為幾類（實際以返回為準）：</p><table tabindex="0"><thead><tr><th>代理識別的類型</th><th>常見 reason / 線索</th><th>典型特徵</th></tr></thead><tbody><tr><td><strong>配額耗盡</strong></td><td><code>QUOTA_EXHAUSTED</code> / 文字包含 <code>exhausted</code>、<code>quota</code></td><td>可能需要等到配額刷新</td></tr><tr><td><strong>速率限制</strong></td><td><code>RATE_LIMIT_EXCEEDED</code> / 文字包含 <code>per minute</code>、<code>rate limit</code>、<code>too many requests</code></td><td>通常是幾十秒等級的冷卻</td></tr><tr><td><strong>模型容量不足</strong></td><td><code>MODEL_CAPACITY_EXHAUSTED</code> / 文字包含 <code>model_capacity</code></td><td>常見是短暫過載，稍後可恢復</td></tr><tr><td><strong>未知</strong></td><td>無法解析</td><td>走預設冷卻策略</td></tr></tbody></table></div><h3 id="antigravity-tools-的自動處理" tabindex="-1">Antigravity Tools 的自動處理 <a class="header-anchor" href="#antigravity-tools-的自動處理" aria-label="Permalink to &quot;Antigravity Tools 的自動處理&quot;">​</a></h3><p>當一次請求遇到 429（以及部分 5xx/過載狀態）時，代理通常會在伺服器端做兩件事：</p><ol><li><strong>記錄冷卻時間</strong>：把這次錯誤寫入 <code>RateLimitTracker</code>，後續選帳號時會主動避開「仍在冷卻」的帳號。</li><li><strong>在重試裡輪換帳號</strong>：Handlers 會在單次請求內進行多次嘗試，重試時會 <code>force_rotate=true</code>，從而觸發 TokenManager 選擇下一個可用帳號。</li></ol><div class="tip custom-block"><p class="custom-block-title">你怎麼知道它有沒有換號？</p><p>即使你的請求 body 不變，響應裡通常會帶 <code>X-Account-Email</code>（以及 <code>X-Mapped-Model</code>），你可以用它驗證「這次請求到底用的是哪個帳號」。</p></div><h2 id="什麼時候會遇到-429-錯誤" tabindex="-1">什麼時候會遇到 429 錯誤？ <a class="header-anchor" href="#什麼時候會遇到-429-錯誤" aria-label="Permalink to &quot;什麼時候會遇到 429 錯誤？&quot;">​</a></h2><h3 id="場景-1-單個帳號請求過快" tabindex="-1">場景 1：單個帳號請求過快 <a class="header-anchor" href="#場景-1-單個帳號請求過快" aria-label="Permalink to &quot;場景 1：單個帳號請求過快&quot;">​</a></h3><p><strong>現象</strong>：即使只有一個帳號，短時間內發送大量請求也會觸發 429。</p><p><strong>原因</strong>：每個帳號都有自己的速率限制（RPM/TPM），超過就會限流。</p><p><strong>解決</strong>：</p><ul><li>增加帳號數量</li><li>降低請求頻率</li><li>使用固定帳號模式分散壓力（詳見「固定帳號模式」）</li></ul><h3 id="場景-2-所有帳號同時限流" tabindex="-1">場景 2：所有帳號同時限流 <a class="header-anchor" href="#場景-2-所有帳號同時限流" aria-label="Permalink to &quot;場景 2：所有帳號同時限流&quot;">​</a></h3><p><strong>現象</strong>：有多個帳號，但所有帳號都返回 429。</p><p><strong>原因</strong>：</p><ul><li>帳號總數不足以支撐你的請求頻率</li><li>所有帳號幾乎同時觸發限流/過載</li></ul><p><strong>解決</strong>：</p><ul><li>增加更多帳號</li><li>調整調度模式為「效能優先」（跳過黏性會話與 60s 視窗複用）</li><li>檢查配額保護是否誤將可用帳號排除</li></ul><h3 id="場景-3-帳號被配額保護誤判" tabindex="-1">場景 3：帳號被配額保護誤判 <a class="header-anchor" href="#場景-3-帳號被配額保護誤判" aria-label="Permalink to &quot;場景 3：帳號被配額保護誤判&quot;">​</a></h3><p><strong>現象</strong>：某個帳號的配額很充足，但系統一直跳過它。</p><p><strong>原因</strong>：</p><ul><li>開啟了<strong>配額保護</strong>，閾值設定偏高</li><li>該帳號的特定模型配額低於閾值</li><li>帳號被手動標記為 <code>proxy_disabled</code></li></ul><p><strong>解決</strong>：</p><ul><li>檢查配額保護設定（Settings → Quota Protection），按你的使用強度調整閾值與監控模型</li><li>在帳號資料中檢查 <code>protected_models</code>，確認是不是被保護策略跳過</li></ul><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-識別-429-錯誤類型" tabindex="-1">第 1 步：識別 429 錯誤類型 <a class="header-anchor" href="#第-1-步-識別-429-錯誤類型" aria-label="Permalink to &quot;第 1 步：識別 429 錯誤類型&quot;">​</a></h3><p><strong>為什麼</strong>：不同類型的 429 錯誤需要不同的處理方式。</p><p>在 Proxy Monitor 中查看 429 錯誤的響應體，重點看兩類資訊：</p><ul><li><strong>原因</strong>：<code>error.details[0].reason</code>（例如 <code>RATE_LIMIT_EXCEEDED</code>、<code>QUOTA_EXHAUSTED</code>）或 <code>error.message</code></li><li><strong>等待時間</strong>：<code>RetryInfo.retryDelay</code> 或 <code>details[0].metadata.quotaResetDelay</code>（如果存在）</li></ul><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;RATE_LIMIT_EXCEEDED&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;metadata&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">          &quot;quotaResetDelay&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;42s&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>你應該看到</strong>：</p><ul><li>如果響應體裡能找到等待時間（例如 <code>RetryInfo.retryDelay</code> 或 <code>quotaResetDelay</code>），代理通常會先等待一小段時間再重試。</li><li>如果沒有等待時間，代理會按內建策略給這個帳號加一個「冷卻期」，並在重試裡直接換下一個帳號。</li></ul><h3 id="第-2-步-檢查帳號調度設定" tabindex="-1">第 2 步：檢查帳號調度設定 <a class="header-anchor" href="#第-2-步-檢查帳號調度設定" aria-label="Permalink to &quot;第 2 步：檢查帳號調度設定&quot;">​</a></h3><p><strong>為什麼</strong>：調度設定直接影響帳號輪換頻率和優先級。</p><p>進入 <strong>API Proxy</strong> 頁面，查看調度策略：</p><table tabindex="0"><thead><tr><th>設定項</th><th>說明</th><th>預設值/建議</th></tr></thead><tbody><tr><td><strong>Scheduling Mode</strong></td><td>調度模式</td><td><code>Balance</code>（預設）</td></tr><tr><td><strong>Preferred Account</strong></td><td>固定帳號模式</td><td>未選取（預設）</td></tr></tbody></table><p><strong>調度模式對比</strong>：</p><table tabindex="0"><thead><tr><th>模式</th><th>帳號複用策略</th><th>限流處理</th><th>適用場景</th></tr></thead><tbody><tr><td><strong>CacheFirst</strong></td><td>啟用黏性會話與 60s 視窗複用</td><td><strong>優先等待</strong>，極大提升 Prompt Caching 命中率</td><td>對話類/需要高快取命中率</td></tr><tr><td><strong>Balance</strong></td><td>啟用黏性會話與 60s 視窗複用</td><td><strong>立即切換</strong>到備選帳號，兼顧成功率和效能</td><td>通用場景，預設</td></tr><tr><td><strong>PerformanceFirst</strong></td><td>跳過黏性會話與 60s 視窗複用，純輪詢模式</td><td>立即切換，帳號負載最均衡</td><td>高併發、無狀態請求</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">快取優先 vs 平衡模式</p><p>如果你使用 Prompt Caching 且希望提升快取命中率，選擇 <code>CacheFirst</code> —— 限流時它會優先等待而不是立即換號。如果你更看重請求成功率而不是快取，選擇 <code>Balance</code> —— 限流時它會立即換號。</p></div><div class="tip custom-block"><p class="custom-block-title">效能優先模式</p><p>如果你的請求是無狀態的（如圖片生成、獨立查詢），可以試試 <code>PerformanceFirst</code>。它會跳過黏性會話與 60s 視窗複用，讓連續請求更容易落到不同帳號。</p></div><h3 id="第-3-步-驗證帳號輪換是否正常工作" tabindex="-1">第 3 步：驗證帳號輪換是否正常工作 <a class="header-anchor" href="#第-3-步-驗證帳號輪換是否正常工作" aria-label="Permalink to &quot;第 3 步：驗證帳號輪換是否正常工作&quot;">​</a></h3><p><strong>為什麼</strong>：確認系統能夠自動切換帳號。</p><p><strong>方法 1：看響應 Header</strong></p><p>用 curl 或你自己的客戶端把響應頭印出來，觀察 <code>X-Account-Email</code> 是否會變化。</p><p><strong>方法 2：查看日誌</strong></p><p>打開日誌檔案（根據你的系統位置），搜尋 <code>🔄 [Token Rotation]</code>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔄 [Token Rotation] Accounts: [</span></span>
<span class="line"><span>  &quot;account1@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account2@example.com(protected=[])&quot;,</span></span>
<span class="line"><span>  &quot;account3@example.com(protected=[])&quot;</span></span>
<span class="line"><span>]</span></span></code></pre></div><p><strong>方法 3：使用 Proxy Monitor</strong></p><p>在 <strong>Monitor</strong> 頁面查看請求日誌，關注：</p><ul><li><strong>Account</strong> 欄位是否在不同帳號間切換</li><li><strong>Status</strong> 為 429 的請求後，是否有成功的請求使用了不同帳號</li></ul><p><strong>你應該看到</strong>：</p><ul><li>當某個帳號返回 429 後，後續請求自動切換到其他帳號</li><li>如果看到多個請求使用同一帳號且都失敗，可能是調度設定問題</li></ul><h3 id="第-4-步-優化帳號優先級" tabindex="-1">第 4 步：優化帳號優先級 <a class="header-anchor" href="#第-4-步-優化帳號優先級" aria-label="Permalink to &quot;第 4 步：優化帳號優先級&quot;">​</a></h3><p><strong>為什麼</strong>：讓系統優先使用高配額/高等級帳號，減少 429 機率。</p><p>在 TokenManager 裡，系統會在選擇帳號前對帳號池做一次排序（會列印 <code>🔄 [Token Rotation] Accounts: ...</code>）：</p><ol><li><strong>訂閱等級優先</strong>：ULTRA &gt; PRO &gt; FREE</li><li><strong>配額百分比優先</strong>：同等級內，配額高的在前</li><li><strong>排序入口</strong>：這個排序發生在代理側，最終用哪個帳號以代理側排序+可用性判斷為準。</li></ol><div class="info custom-block"><p class="custom-block-title">智慧排序原理（代理側）</p><p>優先級是 <code>ULTRA &gt; PRO &gt; FREE</code>；同一訂閱等級內按 <code>remaining_quota</code>（帳號最大剩餘配額百分比）降序。</p></div><p><strong>操作</strong>：</p><ul><li>拖曳帳號調整顯示順序（可選）</li><li>刷新配額（Accounts → 刷新所有配額）</li><li>檢查帳號的訂閱等級和配額</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="❌-錯誤-1-誤將-429-當成「模型沒容量」" tabindex="-1">❌ 錯誤 1：誤將 429 當成「模型沒容量」 <a class="header-anchor" href="#❌-錯誤-1-誤將-429-當成「模型沒容量」" aria-label="Permalink to &quot;❌ 錯誤 1：誤將 429 當成「模型沒容量」&quot;">​</a></h3><p><strong>現象</strong>：看到 429 錯誤就以為模型沒容量了。</p><p><strong>正確理解</strong>：</p><ul><li>429 是<strong>限流</strong>，不是容量問題</li><li>增加帳號可以降低 429 機率</li><li>調整調度模式可以提升切換速度</li></ul><h3 id="❌-錯誤-2-配額保護閾值設定過高" tabindex="-1">❌ 錯誤 2：配額保護閾值設定過高 <a class="header-anchor" href="#❌-錯誤-2-配額保護閾值設定過高" aria-label="Permalink to &quot;❌ 錯誤 2：配額保護閾值設定過高&quot;">​</a></h3><p><strong>現象</strong>：配額充足但系統一直跳過帳號。</p><p><strong>原因</strong>：Quota Protection 會把低於閾值的模型加入帳號的 <code>protected_models</code>，代理在調度時會跳過「被保護的模型」。閾值過高時，可能導致可用帳號被過度排除。</p><p><strong>修正</strong>：</p><ul><li>回到 <strong>Settings → Quota Protection</strong>，調整監控模型與閾值</li><li>如果你想搞清楚它到底保護了哪些模型，去帳號資料裡看 <code>protected_models</code></li></ul><h3 id="❌-錯誤-3-固定帳號模式導致無法輪換" tabindex="-1">❌ 錯誤 3：固定帳號模式導致無法輪換 <a class="header-anchor" href="#❌-錯誤-3-固定帳號模式導致無法輪換" aria-label="Permalink to &quot;❌ 錯誤 3：固定帳號模式導致無法輪換&quot;">​</a></h3><p><strong>現象</strong>：設定了 <code>Preferred Account</code>，但該帳號限流後系統「卡住」。</p><p><strong>原因</strong>：固定帳號模式下，系統優先使用指定帳號，只有在帳號不可用時才降級到輪詢。</p><p><strong>修正</strong>：</p><ul><li>如果不需要固定帳號，清空 <code>Preferred Account</code></li><li>或確保固定帳號的配額充足，避免限流</li></ul><h2 id="檢查點-✅" tabindex="-1">檢查點 ✅ <a class="header-anchor" href="#檢查點-✅" aria-label="Permalink to &quot;檢查點 ✅&quot;">​</a></h2><ul><li>[ ] 能區分配額不足和上游限流</li><li>[ ] 知道如何在 Proxy Monitor 中查看 429 錯誤詳情</li><li>[ ] 理解三種調度模式的區別和使用場景</li><li>[ ] 知道如何檢查帳號輪換是否正常工作</li><li>[ ] 能優化帳號優先級並檢查配額保護策略</li></ul><h2 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h2><h3 id="q1-為什麼我有多個帳號-還是會遇到-429" tabindex="-1">Q1：為什麼我有多個帳號，還是會遇到 429？ <a class="header-anchor" href="#q1-為什麼我有多個帳號-還是會遇到-429" aria-label="Permalink to &quot;Q1：為什麼我有多個帳號，還是會遇到 429？&quot;">​</a></h3><p>A：可能的原因：</p><ol><li>所有帳號同時觸發限流（請求頻率過高）</li><li>連續請求在「60s 視窗複用」下反反覆複用同一帳號，更容易把單帳號打到限流</li><li>配額保護誤將可用帳號排除</li><li>帳號總數不足以支撐你的請求頻率</li></ol><p><strong>解決</strong>：</p><ul><li>增加更多帳號</li><li>使用 <code>PerformanceFirst</code> 模式</li><li>檢查 Quota Protection 是否把你要用的模型加入了 <code>protected_models</code>（必要時調整監控模型與閾值）</li><li>降低請求頻率</li></ul><h3 id="q2-429-錯誤會自動重試嗎" tabindex="-1">Q2：429 錯誤會自動重試嗎？ <a class="header-anchor" href="#q2-429-錯誤會自動重試嗎" aria-label="Permalink to &quot;Q2：429 錯誤會自動重試嗎？&quot;">​</a></h3><p>A：會在單次請求內自動重試。<strong>重試次數上限通常是 3 次</strong>，具體計算方式為 <code>min(3, 帳號池大小)</code>，且至少嘗試 1 次。</p><p><strong>重試次數範例</strong>：</p><ul><li>帳號池 1 個帳號 → 嘗試 1 次（不重試）</li><li>帳號池 2 個帳號 → 嘗試 2 次（重試 1 次）</li><li>帳號池 3 個或更多帳號 → 嘗試 3 次（重試 2 次）</li></ul><p><strong>大致流程</strong>：</p><ol><li>記錄限流/過載資訊（進入 <code>RateLimitTracker</code>）</li><li>如果能解析到等待時間（例如 <code>RetryInfo.retryDelay</code> / <code>quotaResetDelay</code>），會先等待一小段時間再繼續</li><li>重試時強制輪換帳號（<code>attempt &gt; 0</code> 時 <code>force_rotate=true</code>），嘗試用下一個可用帳號發起上游請求</li></ol><p>如果所有嘗試都失敗，代理會把錯誤返回給客戶端；同時你仍然可以從響應頭（如 <code>X-Account-Email</code>）或 Proxy Monitor 看到實際使用過的帳號。</p><h3 id="q3-如何查看某個帳號被限流了多久" tabindex="-1">Q3：如何查看某個帳號被限流了多久？ <a class="header-anchor" href="#q3-如何查看某個帳號被限流了多久" aria-label="Permalink to &quot;Q3：如何查看某個帳號被限流了多久？&quot;">​</a></h3><p>A：有兩種方式：</p><p><strong>方式 1</strong>：查看日誌，搜尋 <code>rate-limited</code></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🔒 [FIX #820] Preferred account xxx@gmail.com is rate-limited, falling back to round-robin</span></span></code></pre></div><p><strong>方式 2</strong>：日誌中會顯示剩餘等待時間</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>All accounts are currently limited. Please wait 30s.</span></span></code></pre></div><h3 id="q4-配額保護和限流是一回事嗎" tabindex="-1">Q4：配額保護和限流是一回事嗎？ <a class="header-anchor" href="#q4-配額保護和限流是一回事嗎" aria-label="Permalink to &quot;Q4：配額保護和限流是一回事嗎？&quot;">​</a></h3><p>A：不是。</p><table tabindex="0"><thead><tr><th>特性</th><th>配額保護</th><th>限流追蹤</th></tr></thead><tbody><tr><td><strong>觸發條件</strong></td><td>模型配額低於閾值</td><td>收到 429 錯誤</td></tr><tr><td><strong>作用範圍</strong></td><td>特定模型</td><td>整個帳號</td></tr><tr><td><strong>持續時間</strong></td><td>直到配額恢復</td><td>由上游決定（通常幾秒到幾分鐘）</td></tr><tr><td><strong>行為</strong></td><td>跳過該模型</td><td>跳過該帳號</td></tr></tbody></table><h3 id="q5-如何強制立即切換帳號" tabindex="-1">Q5：如何強制立即切換帳號？ <a class="header-anchor" href="#q5-如何強制立即切換帳號" aria-label="Permalink to &quot;Q5：如何強制立即切換帳號？&quot;">​</a></h3><p>A：可以從「讓下一次請求更容易換號」的角度入手：</p><ol><li><strong>調度層面</strong>：切到 <code>PerformanceFirst</code>，跳過黏性會話與 60s 視窗複用</li><li><strong>固定帳號</strong>：如果啟用了 <code>Preferred Account</code>，先清空它，否則會優先用固定帳號（直到它限流/被保護）</li><li><strong>帳號池</strong>：增加帳號數量，單帳號被限流時更容易找到替代帳號</li></ol><p>單次請求裡，代理本身也會在重試時強制輪換（<code>attempt &gt; 0</code> 會觸發 <code>force_rotate=true</code>），但重試次數受上限控制。</p><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><ul><li>429 在 Antigravity Tools 裡是一類「上游暫時不可用」的訊號，可能是速率限制、配額耗盡、模型容量不足等原因</li><li>代理會記錄冷卻時間，並在單次請求的重試裡嘗試輪換帳號（但重試次數有限）</li><li>調度模式、Quota Protection、帳號數量都會影響你遇到 429 的機率與恢復速度</li><li>用 Proxy Monitor、響應頭 <code>X-Account-Email</code> 和日誌可以快速定位問題</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../404-base-url/">404/路徑不相容：Base URL、/v1 前綴與「疊路徑」客戶端</a></strong>。</p><p>你會學到：</p><ul><li>最常見的接入錯誤（404）是如何產生的</li><li>不同客戶端對 base_url 的拼接差異</li><li>如何快速修復 404 問題</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>429 重試延遲解析（RetryInfo / quotaResetDelay）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L38-L67" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>38-67</td></tr><tr><td>Duration 解析工具</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/upstream/retry.rs#L11-L35" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/upstream/retry.rs</code></a></td><td>11-35</td></tr><tr><td>調度模式列舉（CacheFirst/Balance/PerformanceFirst）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/sticky_config.rs#L3-L12" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/sticky_config.rs</code></a></td><td>3-12</td></tr><tr><td>限流原因解析與預設冷卻策略</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/rate_limit.rs#L5-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/rate_limit.rs</code></a></td><td>5-258</td></tr><tr><td>MAX_RETRY_ATTEMPTS 常數定義（OpenAI handler）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L14" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>14</td></tr><tr><td>重試次數計算（max_attempts = min(MAX_RETRY_ATTEMPTS, pool_size)）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L830" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>830</td></tr><tr><td>OpenAI handler：429/5xx 時標記限流並重試/輪換</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/openai.rs#L349-L389" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/openai.rs</code></a></td><td>349-389</td></tr><tr><td>帳號排序優先級（ULTRA &gt; PRO &gt; FREE + remaining_quota）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L504-L538" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>504-538</td></tr><tr><td>60s 視窗複用 + 避開限流/配額保護</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L624-L739" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>624-739</td></tr><tr><td>限流記錄入口（mark_rate_limited）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1089-L1113" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1089-1113</td></tr><tr><td>429 精確鎖定/即時配額刷新/降級策略（mark_rate_limited_async）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L1258-L1417" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>1258-1417</td></tr></tbody></table><p><strong>關鍵常數</strong>：</p><ul><li><code>MAX_RETRY_ATTEMPTS = 3</code>：單次請求內最大重試次數（OpenAI/Gemini handler）</li><li><code>60</code>：60 秒視窗複用（僅在 <code>PerformanceFirst</code> 之外的模式啟用）</li><li><code>5</code>：Token 獲取逾時時間（秒）</li><li><code>300</code>：Token 提前刷新閾值（秒，5 分鐘）</li></ul><p><strong>關鍵函數</strong>：</p><ul><li><code>parse_retry_delay()</code>：從 429 錯誤響應中提取重試延遲</li><li><code>get_token_internal()</code>：帳號選擇與輪換的核心邏輯</li><li><code>mark_rate_limited()</code>：標記帳號為限流狀態</li></ul></details>`,116)])])}const u=a(i,[["render",s]]);export{g as __pageData,u as default};
